// Frame represents a single animation frame
type Frame struct {
	Duration time.Duration
	Content  []string
	FgColors map[string]string // Maps "x,y" -> color key
	BgColors map[string]string // Maps "x,y" -> color key
}

// Model is the Bubbletea model for the animation
type Model struct {
	frames            []Frame
	frameIndex        int
	isPlaying         bool
	loop              bool
	width             int
	height            int
	hasDarkBackground bool
}

type tickMsg time.Time

// New creates a new animation model
// Set hasDarkBackground to true for dark terminals, false for light terminals
// width and height set the render dimensions (use 0 for default)
func New(hasDarkBackground bool, width, height int) Model {
	if width <= 0 {
		width = 100
	}
	if height <= 0 {
		height = 34
	}
	return Model{
		frames:            frames,
		frameIndex:        0,
		isPlaying:         true,
		loop:              false,
		width:             width,
		height:            height,
		hasDarkBackground: hasDarkBackground,
	}
}

// NewWithDefaults creates a new animation model with dark background (default)
func NewWithDefaults() Model {
	return New(true, 0, 0)
}

// NewWithDimensions creates a new animation model with custom dimensions
func NewWithDimensions(width, height int, hasDarkBackground bool) Model {
	return New(hasDarkBackground, width, height)
}

// Init initializes the model
func (m Model) Init() tea.Cmd {
	return m.tick()
}

func (m Model) tick() tea.Cmd {
	if !m.isPlaying || len(m.frames) == 0 {
		return nil
	}
	return tea.Tick(m.frames[m.frameIndex].Duration, func(t time.Time) tea.Msg {
		return tickMsg(t)
	})
}

// Update handles messages
func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyPressMsg:
		switch msg.String() {
		case "q", "ctrl+c":
			return m, tea.Quit
		}
	case tickMsg:
		if m.isPlaying && len(m.frames) > 0 {
			m.frameIndex++
			if m.frameIndex >= len(m.frames) {
				if m.loop {
					m.frameIndex = 0
				} else {
					m.frameIndex = len(m.frames) - 1
					m.isPlaying = false
					return m, nil
				}
			}
			return m, m.tick()
		}
	}
	return m, nil
}

// getColor returns the appropriate color for the current background mode
func (m Model) getColor(colorKey string) string {
	if m.hasDarkBackground {
		return COLORS_DARK[colorKey]
	}
	return COLORS_LIGHT[colorKey]
}

// View renders the animation
func (m Model) View() tea.View {
	if len(m.frames) == 0 {
		return tea.NewView("")
	}
	frame := m.frames[m.frameIndex]
	var sb strings.Builder

	for y, row := range frame.Content {
		chars := []rune(row)
		for x, ch := range chars {
			key := fmt.Sprintf("%d,%d", x, y)
			style := lipgloss.NewStyle()
			if fgKey, ok := frame.FgColors[key]; ok {
				style = style.Foreground(lipgloss.Color(m.getColor(fgKey)))
			}
			if bgKey, ok := frame.BgColors[key]; ok {
				style = style.Background(lipgloss.Color(m.getColor(bgKey)))
			}
			sb.WriteString(style.Render(string(ch)))
		}
		if y < len(frame.Content)-1 {
			sb.WriteString("\n")
		}
	}
	return tea.NewView(sb.String())
}

// Play starts or resumes the animation
func (m *Model) Play() tea.Cmd {
	m.isPlaying = true
	return m.tick()
}

// Pause stops the animation
func (m *Model) Pause() {
	m.isPlaying = false
}

// Restart resets to the first frame
func (m *Model) Restart() tea.Cmd {
	m.frameIndex = 0
	return m.tick()
}

// IsPlaying returns whether the animation is playing
func (m Model) IsPlaying() bool {
	return m.isPlaying
}

// CurrentFrame returns the current frame index
func (m Model) CurrentFrame() int {
	return m.frameIndex
}

// TotalFrames returns the total number of frames
func (m Model) TotalFrames() int {
	return len(m.frames)
}

